import{f as e,h as t,j as n,t as r}from"./chunks/plugin-vue_export-helper.CkPjATLm.js";const i=JSON.parse(`{"title":"Data Serialization","description":"Data Serialization Formats and Techniques","frontmatter":{"title":"Data Serialization","description":"Data Serialization Formats and Techniques"},"headers":[],"relativePath":"Concepts/Data_Serialization.md","filePath":"Concepts/Data_Serialization.md","lastUpdated":1766945700000}`);var a={name:`Concepts/Data_Serialization.md`};function o(r,i,a,o,s,c){return n(),e(`div`,null,[...i[0]||=[t(`<h1 id="data-serialization" tabindex="-1">Data Serialization <a class="header-anchor" href="#data-serialization" aria-label="Permalink to “Data Serialization”">​</a></h1><p>Data serialization is the process of converting data structures or objects into a format that can be easily stored, transmitted, and reconstructed later</p><ul><li><strong>Pickling</strong>: In Python, the <code>pickle</code> module allows for serializing and deserializing Python objects</li><li><strong>Marshalling</strong>: In languages like Java, marshalling refers to the process of transforming the memory representation of an object to a data format suitable for storage or transmission</li></ul><h2 id="serialization-formats" tabindex="-1">Serialization Formats <a class="header-anchor" href="#serialization-formats" aria-label="Permalink to “Serialization Formats”">​</a></h2><p>Serialization formats vary in terms of human readability, efficiency, and support for complex data types</p><p>Common serialization formats include <a href="./../Languages/JSON.html">JSON</a>, XML, YAML, Protocol Buffers, and MessagePack</p><ul><li>Some are text-based (e.g., JSON, XML, YAML), while others are binary (e.g., Protocol Buffers, MessagePack)</li><li>The choice of format often depends on the specific use case, such as data interchange between systems, configuration files, or data storage</li></ul><p>We can create custom serialization formats for specific use cases such as hiding implementation details or optimizing for specific data structures. But it is generally recommended to use established serialization formats to ensure compatibility and ease of use across different systems and programming languages</p>`,8)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};